mapper.insert:

    select SEQ_SMAIN.nextval from dual

insert into schedule_main (
    schedule_no, schedule_title, schedule_status,
    create_date, schedule_startdate, schedule_enddate,
    schedule_visibility, member_no
) values (
    #{scheduleNo}, #{scheduleTitle}, 'Y',
    sysdate, to_date(#{scheduleStartdate}, 'yyyy-mm-dd'), to_date(#{scheduleEnddate}, 'yyyy-mm-dd'),
    'N', #{memberNo}
)

insert into schedule_sub (
    schedule_sub_no, schedule_sub_date, schedule_sub_seq,
    schedule_no, content_id
) values (
    SEQ_SSUB.nextval, to_date(#{scheduleSubDate}, 'yyyy-mm-dd'), #{scheduleSubSeq},
    #{scheduleNo}, #{contentId}
)

mapper.update:
update schedule_main
   set schedule_status = 'N'
 where schedule_no = #{scheduleNo}
   and member_no = #{memberNo}
